//TEST
const { Web3 } = require("web3");

const localhost = "http://127.0.0.1:7545";
const web3 = new Web3(localhost);

// SimpleUserFlow 合约 ABI（可直接用）
const SIMPLE_USER_FLOW_ABI = [
  {
    anonymous: false,
    inputs: [
      { indexed: true, internalType: "address", name: "user", type: "address" },
      { indexed: false, internalType: "string", name: "oldNickname", type: "string" },
      { indexed: false, internalType: "string", name: "newNickname", type: "string" },
      { indexed: false, internalType: "uint256", name: "timestamp", type: "uint256" },
    ],
    name: "NicknameUpdated",
    type: "event",
  },
  {
    anonymous: false,
    inputs: [
      { indexed: true, internalType: "address", name: "user", type: "address" },
      { indexed: false, internalType: "string", name: "nickname", type: "string" },
      { indexed: false, internalType: "uint256", name: "timestamp", type: "uint256" },
    ],
    name: "UserRegistered",
    type: "event",
  },
  {
    inputs: [],
    name: "getMyProfile",
    outputs: [
      { internalType: "string", name: "nickname", type: "string" },
      { internalType: "uint256", name: "createdAt", type: "uint256" },
      { internalType: "bool", name: "exists", type: "bool" },
    ],
    stateMutability: "view",
    type: "function",
  },
  {
    inputs: [{ internalType: "address", name: "userAddress", type: "address" }],
    name: "isRegistered",
    outputs: [{ internalType: "bool", name: "", type: "bool" }],
    stateMutability: "view",
    type: "function",
  },
  {
    inputs: [{ internalType: "string", name: "nickname", type: "string" }],
    name: "register",
    outputs: [],
    stateMutability: "nonpayable",
    type: "function",
  },
  {
    inputs: [{ internalType: "string", name: "newNickname", type: "string" }],
    name: "updateNickname",
    outputs: [],
    stateMutability: "nonpayable",
    type: "function",
  },
];

// 从 Remix 复制 deployed bytecode 并替换这里（必须带 0x 前缀）
const SIMPLE_USER_FLOW_BYTECODE = "";

async function main() {
  const accounts = await web3.eth.getAccounts();
  console.log("账户列表地址：", accounts);

  if (!SIMPLE_USER_FLOW_BYTECODE || SIMPLE_USER_FLOW_BYTECODE === "0x") {
    console.log("\n请先把 Remix 的 deployed bytecode 粘贴到 SIMPLE_USER_FLOW_BYTECODE，再运行部署测试。\n");
    return;
  }

  const deployer = accounts[0];
  const tester = accounts[1] || accounts[0];

  const contract = new web3.eth.Contract(SIMPLE_USER_FLOW_ABI);
  const deployed = await contract
    .deploy({ data: SIMPLE_USER_FLOW_BYTECODE })
    .send({ from: deployer, gas: 3500000 });

  console.log("合约部署成功，地址：", deployed.options.address);

  // 1) 注册
  await deployed.methods.register("alice").send({ from: deployer, gas: 200000 });
  console.log("register(alice) 完成");

  // 2) 查看自己资料
  const profile1 = await deployed.methods.getMyProfile().call({ from: deployer });
  console.log("getMyProfile(注册后)：", profile1);

  // 3) 更新昵称
  await deployed.methods.updateNickname("alice_new").send({ from: deployer, gas: 200000 });
  console.log("updateNickname(alice_new) 完成");

  // 4) 再次查看
  const profile2 = await deployed.methods.getMyProfile().call({ from: deployer });
  console.log("getMyProfile(更新后)：", profile2);

  // 5) 用另一个账号检查是否已注册
  const registered = await deployed.methods.isRegistered(deployer).call({ from: tester });
  console.log(`isRegistered(${deployer}) =`, registered);
}

main().catch((error) => {
  console.error("执行失败：", error);
});